#include <bits/stdc++.h>using namespace std;int main(){	ios::sync_with_stdio(0);cin.tie(0);	int T;cin>>T;	int a[105],t[3005][2],cnt;	while(T--){		int n;cin>>n;		for(int i=1;i<=n;i++)cin>>a[i];		bool f=1;		for(int i=2;i<=n;i++)if(a[i]!=a[1])f=0;		if(f){cout<<"0\n";continue;}		bool has1=0;		for(int i=1;i<=n;i++)			if(a[i]==1){has1=1;break;}		if(has1){cout<<"-1\n";continue;}		cnt=0;		while(1){			int mx=1,mn=1;			for(int i=2;i<=n;i++){				if(a[i]>a[mx])mx=i;				if(a[i]<a[mn])mn=i;			}			if(a[mx]==a[mn])break;			t[cnt][0]=mx;			t[cnt][1]=mn;			cnt++;			a[mx]=(a[mx]+a[mn]-1)/a[mn];		}		cout<<cnt<<'\n';		for(int i=0;i<cnt;i++)cout<<t[i][0]<<" "<<t[i][1]<<'\n';	}	return 0;}